            // If the bit is 1, flip it to 0 (effectively carrying over).
            x = x ^ m;
            // Move 'm' to the next bit position to the left.
            m <<= 1;
        }
        // At this point, 'm' points to the rightmost 0 bit in the original 'x'
        // (or beyond the most significant bit if 'x' was all 1s, e.g., Integer.MAX_VALUE).
        // Flip this 0 bit to 1.
        x = x ^ m;
        return x;
    }

