    public static int ceilSearch(int[] arr, int low, int high, int x) {
        // If x is smaller than or equal to the first element,
        // then the first element is the ceil.
        if (x <= arr[low]) {
            return low;
        }
        // If x is greater than the last element,
        // then there is no ceil.
        if (x > arr[high]) {
            return -1;
        }
        // Calculate mid to divide the array
        int mid = (low + high) / 2;
        // If x is found at mid, then mid is the ceil
        if (arr[mid] == x) {
            return mid;
        }
        // If arr[mid] is less than x, then ceil must be in the right half
        else if (arr[mid] < x) {
            // Check if mid+1 is within bounds and if x is less than or equal to arr[mid+1].
            // If so, arr[mid+1] is the smallest element greater than or equal to x.
            if (mid + 1 <= high && x <= arr[mid + 1]) {
                return mid + 1;
            }
            // Otherwise, continue searching in the right sub-array
            else {
                return ceilSearch(arr, mid + 1, high, x);
            }
        }
        // If arr[mid] is greater than x, then ceil must be in the left half or mid itself
        else { // arr[mid] > x
            // Check if mid-1 is within bounds and if x is greater than arr[mid-1].
            // If so, arr[mid] is the smallest element greater than or equal to x.
            if (mid - 1 >= low && x > arr[mid - 1]) {
                return mid;
            }
            // Otherwise, continue searching in the left sub-array
            else {
                return ceilSearch(arr, low, mid - 1, x);
            }
        }
    }

