static     public boolean canRepresentBST(int[] pre, int n) {
        Stack<Integer> s = new Stack<>();
        int root = Integer.MIN_VALUE;
        for (int i = 0; i < n; i++) {
            // If we find a node that is smaller than the current root (which is the last popped element),
            // then it's not a valid BST. This means a right child appeared before its parent.
            if (pre[i] < root) {
                return false;
            }
            // While stack is not empty and the current element is greater than the stack's top,
            // it means the stack top is a left child's parent, and the current element is its right child.
            // Pop elements from the stack until we find an element greater than current element.
            // The last popped element will be the parent of the current element (or a previous parent).
            // This popped element becomes the new "root" (lower bound for subsequent right children).
            while (!s.isEmpty() && s.peek() < pre[i]) {
                root = s.pop();
            }
            // Push the current element onto the stack.
            s.push(pre[i]);
        }
