static     public void spiralFill(int m, int n, int[][] a) {
        int val = 1;
        int k = 0, l = 0; // k: starting row index, l: starting column index
        // m: ending row index (exclusive, effectively current bottom boundary + 1)
        // n: ending column index (exclusive, effectively current right boundary + 1)
        while (k < m && l < n) {
            // Fill the top row from the remaining cells
            for (int i = l; i < n; ++i) {
                a[k][i] = val++;
            }
            k++; // Move the top boundary down
            // Fill the rightmost column from the remaining cells
            for (int i = k; i < m; ++i) {
                a[i][n - 1] = val++;
            }
            n--; // Move the right boundary left
            // Fill the bottom row from the remaining cells
            // Only if there's still a row to fill (i.e., top boundary hasn't crossed bottom)
            if (k < m) {
                for (int i = n - 1; i >= l; --i) {
                    a[m - 1][i] = val++;
                }
                m--; // Move the bottom boundary up
            }
            // Fill the leftmost column from the remaining cells
            // Only if there's still a column to fill (i.e., left boundary hasn't crossed right)
            if (l < n) {
                for (int i = m - 1; i >= k; --i) {
                    a[i][l] = val++;
                }
                l++; // Move the left boundary right
            }
        }
    }

