static     public String decToBin(int n) {
        // Base case: if n is 0, its binary representation is "0".
        if (n == 0) {
            return "0";
        }
        // Use StringBuilder for efficient string construction,
        // as repeated String concatenation can be inefficient in Java.
        StringBuilder binBuilder = new StringBuilder();
        // Loop until n becomes 0
        while (n > 0) {
            // Get the least significant bit (LSB) using bitwise AND operation
            // If LSB is 0, append '0'; otherwise, append '1'.
            char digit = ((n & 1) == 0 ? '0' : '1');
            // Prepend the digit to the binary string.
            // This builds the string in the correct MSB-to-LSB order.
            binBuilder.insert(0, digit);
            // Right-shift n by 1 bit, effectively dividing n by 2
            // and discarding the LSB that was just processed.
            n >>= 1;
        }
        // Convert the StringBuilder content to a String and return.
        return binBuilder.toString();
    }

