            // 2. Exclude the nth item: result of knapsack for same capacity W and remaining items (n-1).
            return Math.max(val[n - 1] + knapSack(W - wt[n - 1], wt, val, n - 1),
                            knapSack(W, wt, val, n - 1));
        }
    }

