static     public int turnOffK(int n, int k) {
        // If k is non-positive, no bit needs to be turned off,
        // so return n as is.
        if (k <= 0) {
            return n;
        }
        // Calculate a mask to clear the k-th bit.
        // 1. (k - 1) gives the 0-indexed position of the bit.
        // 2. (1 << (k - 1)) creates a number with only the k-th bit set.
        //    (e.g., if k=1, mask is 0001; if k=2, mask is 0010; if k=3, mask is 0100)
        // 3. ~(...) performs a bitwise NOT on this mask. This results in a number
        //    where all bits are 1 except for the k-th bit, which is 0.
        //    (e.g., if k=2, mask is 0010, ~mask is 1101)
        // 4. n & (...) performs a bitwise AND operation between n and the
        //    inverted mask. This effectively clears the k-th bit of n
        //    while leaving all other bits unchanged.
        return (n & ~(1 << (k - 1)));
    }

