                    // If the priority queue already has k elements,
                    // and the current sum is greater than the smallest element in the queue (Q.peek()),
                    // then remove the smallest and add the current sum.
                    if (Q.peek() < currentSubarraySum) {
                        Q.poll(); // poll() is similar to C++ pop()
                        Q.offer(currentSubarraySum);
                    }
