static     public int breakSum(int n) {
        // dp[i] stores the maximum sum achievable for integer i.
        int[] dp = new int[n + 1];
        // Base cases
        if (n >= 0) {
            dp[0] = 0;
        }
        if (n >= 1) {
            dp[1] = 1;
        }
        // Fill the dp table using the recurrence relation
        for (int i = 2; i <= n; i++) {
            // The recurrence relation: dp[i] = max(dp[i/2] + dp[i/3] + dp[i/4], i)
            // Integer division (i/2, i/3, i/4) automatically truncates,
            // which is the desired behavior for this problem.
            dp[i] = Math.max(dp[i / 2] + dp[i / 3] + dp[i / 4], i);
        }
        // The result for n is stored in dp[n]
        return dp[n];
    }

