    public static int isMultipleOf3(int n) {
        int odd_count = 0;
        int even_count = 0;
        // Handle negative numbers by converting to positive, as divisibility by 3
        // is the same for n and -n.
        if (n < 0) {
            n = -n;
        }
        // Base cases
        if (n == 0) {
            return 1; // 0 is a multiple of 3
        }
        if (n == 1) {
            return 0; // 1 is not a multiple of 3
        }
        // Iterate while n is not zero
        while (n != 0) {
            // Check the 0th bit (least significant bit - odd position)
            if ((n & 1) == 1) {
                odd_count++;
            }
            // Check the 1st bit (second least significant bit - even position)
            if ((n & 2) == 2) { // Equivalent to ((n >> 1) & 1) == 1
                even_count++;
            }
            // Right shift n by 2 bits to process the next pair of bits (2nd and 3rd, then 4th and 5th, etc.)
            n = n >> 2;
        }
        // Recursively call the function with the absolute difference of counts.
        // This is based on the divisibility rule for 3 using alternating sum of digits (in base 4).
        return isMultipleOf3(Math.abs(odd_count - even_count));
    }

